mutations.find:
timer1_write_control(timer, 0u);
timer1_write_status_clear(timer, TIMER1_STATUS_ALL);
timer1_write_compare(timer, 0u);
timer1_write_control(timer, TIMER1_CONTROL_READY);

mutations.replace:
timer1_write_control(timer, 0u);
timer1_write_control(timer, TIMER1_CONTROL_READY);
timer1_write_status_clear(timer, TIMER1_STATUS_ALL);
timer1_write_compare(timer, 0u);
